import { valueContent } from './SeriesItem.sty.js';
import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { DEFAULT_TRUNCATION_MODE } from '../../../../../constants.js';
import { ChartTextEllipsis } from '../../../../text-ellipsis/ChartTextEllipsis.js';
import { TooltipValueContent } from '../../../section-components/TooltipValueContent/TooltipValueContent.js';

interface SeriesItemValueProps {
  truncationMode: TruncationMode;
  value: string | string[];
}

export const SeriesItemValue = (props: SeriesItemValueProps) => {
  const { truncationMode = DEFAULT_TRUNCATION_MODE, value } = props;
  const multipleValues = Array.isArray(value);

  return multipleValues ? (
    value.slice(0, 2).map((v, index) => (
      <TooltipValueContent
        key={`${v}-${index}`}
        variant="chip"
        className={valueContent}
      >
        <ChartTextEllipsis
          truncationMode={truncationMode}
          aria-label="Value serie name"
        >
          {v}
        </ChartTextEllipsis>
      </TooltipValueContent>
    ))
  ) : (
    <TooltipValueContent variant="chip" className={valueContent}>
      <ChartTextEllipsis
        truncationMode={truncationMode}
        aria-label="Value serie name"
      >
        {value}
      </ChartTextEllipsis>
    </TooltipValueContent>
  );
};
